SELECT item_code, item_name, SUM(quantity_sold) AS total_quantity, SUM(quantity_sold * sale_price) AS total_revenue, AVG(sale_price) AS avg_price, COUNT(DISTINCT DATE(sale_timestamp)) AS active_days FROM item_quarterly_sales WHERE year = #{year} AND quarter = #{quarter}
AND item_code LIKE CONCAT(#{category}, '%')
GROUP BY item_code, item_name ORDER BY total_revenue DESC

SELECT sales_id
FROM item_quarterly_sales
WHERE item_code = #{itemCode}
AND item_name = #{itemName}
AND sale_price = #{salePrice}
AND year = #{year}
AND quarter = #{quarter}

mapper.update:
CREATE TEMPORARY TABLE IF NOT EXISTS tmp_grouped_items ( item_code VARCHAR(10) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci, item_name VARCHAR(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci, sale_price DECIMAL(8,2), total_quantity INT, group_key VARCHAR(200) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci ) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci;
TRUNCATE TABLE tmp_grouped_items;
INSERT INTO tmp_grouped_items (item_code, item_name, sale_price, total_quantity, group_key) SELECT mi.item_code, mi.name AS item_name, oi.price_at_order AS sale_price, SUM(oi.quantity) AS total_quantity, CONCAT(mi.item_code, '|', mi.name, '|', oi.price_at_order) COLLATE utf8mb4_unicode_ci AS group_key FROM order_items oi JOIN menu_items mi ON oi.item_id = mi.item_id WHERE oi.order_id = #{orderId} GROUP BY mi.item_code, mi.name, oi.price_at_order;
UPDATE item_quarterly_sales iqs INNER JOIN tmp_grouped_items gi ON CONCAT(iqs.item_code, '|', iqs.item_name, '|', iqs.sale_price) COLLATE utf8mb4_unicode_ci = gi.group_key COLLATE utf8mb4_unicode_ci SET iqs.quantity_sold = iqs.quantity_sold + gi.total_quantity, iqs.sale_timestamp = NOW() WHERE iqs.year = #{year} AND iqs.quarter = #{quarter};
INSERT INTO item_quarterly_sales (item_code, item_name, sale_price, quantity_sold, sale_timestamp, year, quarter) SELECT gi.item_code, gi.item_name, gi.sale_price, gi.total_quantity, NOW(), #{year}, #{quarter} FROM tmp_grouped_items gi WHERE NOT EXISTS ( SELECT 1 FROM item_quarterly_sales iqs WHERE CONCAT(iqs.item_code, '|', iqs.item_name, '|', iqs.sale_price) COLLATE utf8mb4_unicode_ci = gi.group_key COLLATE utf8mb4_unicode_ci AND iqs.year = #{year} AND iqs.quarter = #{quarter} );
DROP TEMPORARY TABLE IF EXISTS tmp_grouped_items;

