SELECT COALESCE(
MAX(CAST(SUBSTRING_INDEX(order_number, '-', -1) AS UNSIGNED)),
0
) + 1
FROM table_orders
WHERE order_number LIKE CONCAT(#{prefix}, '-', #{dateStr}, '-%')

    AND order_type = #{orderType}


    AND delivery_method = #{deliveryMethod}

