SELECT oi.order_item_id, oi.order_id, oi.item_id, oi.quantity, oi.served_quantity,oi.prepared_quantity, oi.status, oi.price_at_order, oi.assigned_table_display_id, oi.served_table_display_id, oi.quantity_distribution, mi.item_code, mi.name AS item_name FROM table_orders o JOIN order_items oi ON o.order_id = oi.order_id JOIN menu_items mi ON oi.item_id = mi.item_id JOIN restaurant_tables t ON o.table_id = t.table_id WHERE t.display_id IN
#{displayId}
AND o.status = 'ORDERED' ORDER BY oi.assigned_table_display_id, oi.order_item_id ASC
